import{bV as s,aL as a,u as p,G as l}from"./chunks/framework.D_inzUUb.js";const _=JSON.parse('{"title":"组织生成","description":"","frontmatter":{},"headers":[],"relativePath":"mumuainovel/组织生成.md","filePath":"mumuainovel/组织生成.md","lastUpdated":1777687820000}'),t={name:"mumuainovel/组织生成.md"};function e(i,n,o,c,u,q){return a(),p("div",null,[...n[0]||(n[0]=[l(`<h1 id="组织生成" tabindex="-1">组织生成 <a class="header-anchor" href="#组织生成" aria-label="Permalink to &quot;组织生成&quot;">​</a></h1><blockquote><p>模板键: <code>SINGLE_ORGANIZATION_GENERATION</code> 分类: 角色生成 描述: 生成组织/势力的详细设定 参数: [&quot;project_context&quot;, &quot;user_input&quot;]</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;system&gt;</span></span>
<span class="line"><span>你是专业的组织设定师，擅长创建完整的组织/势力设定。</span></span>
<span class="line"><span>&lt;/system&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;task&gt;</span></span>
<span class="line"><span>【设计任务】</span></span>
<span class="line"><span>根据用户需求和项目上下文，创建一个完整的组织/势力设定。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【命名要求】</span></span>
<span class="line"><span>如果项目上下文中已有组织，新组织的命名风格必须与已有组织保持一致。</span></span>
<span class="line"><span>参考已有组织的名称规律（用词习惯、字数、文化风格），生成符合同一世界观的新组织名称。</span></span>
<span class="line"><span>&lt;/task&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;context priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【项目上下文】</span></span>
<span class="line"><span>{project_context}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【用户需求】</span></span>
<span class="line"><span>{user_input}</span></span>
<span class="line"><span>&lt;/context&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;naming_guidelines priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【各类型组织命名风格】</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**现代都市**：公司用全称/简称（盛华集团、锐思科技）、机构用正式名称（市公安局、第一人民医院）</span></span>
<span class="line"><span>**玄幻仙侠**：用意境词+门派词（天剑宗、幽冥殿、星辰阁、万兽山庄）</span></span>
<span class="line"><span>**科幻**：用编号/代号/功能名（第七舰队、量子研究所、新星联邦）</span></span>
<span class="line"><span>**历史古代**：用朝代+职能（锦衣卫、漕帮、翰林院）</span></span>
<span class="line"><span>**奇幻魔法**：用象征词+组织词（银月骑士团、暗影议会、魔法师协会、冒险者工会、龙语学院）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【命名原则】</span></span>
<span class="line"><span>- 参考项目中已有组织的命名风格，保持高度一致</span></span>
<span class="line"><span>- 名称要有文化代入感，不要用现代词汇套古代背景</span></span>
<span class="line"><span>- 组织名称长度2-6个字为佳</span></span>
<span class="line"><span>- 如果已有组织名称都是&quot;XX宗/XX阁/XX殿&quot;格式，新组织也用相同格式</span></span>
<span class="line"><span>- 如果已有组织名称都是现代公司名格式，新组织也用相同格式</span></span>
<span class="line"><span>&lt;/naming_guidelines&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;output priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【输出格式】</span></span>
<span class="line"><span>生成完整的组织设定JSON对象：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>  &quot;name&quot;: &quot;组织名称（必须符合已有组织的命名风格，如用户未提供则生成符合世界观的名称）&quot;,</span></span>
<span class="line"><span>  &quot;is_organization&quot;: true,</span></span>
<span class="line"><span>  &quot;organization_type&quot;: &quot;组织类型（帮派/公司/门派/学院/政府机构/宗教组织等）&quot;,</span></span>
<span class="line"><span>  &quot;personality&quot;: &quot;组织特性（150-200字）：核心理念、行事风格、文化价值观、运作方式&quot;,</span></span>
<span class="line"><span>  &quot;background&quot;: &quot;组织背景（200-300字）：建立历史、发展历程、重要事件、当前地位&quot;,</span></span>
<span class="line"><span>  &quot;appearance&quot;: &quot;外在表现（100-150字）：总部位置、标志性建筑、组织标志、制服等&quot;,</span></span>
<span class="line"><span>  &quot;organization_purpose&quot;: &quot;组织目的和宗旨：明确目标、长期愿景、行动准则&quot;,</span></span>
<span class="line"><span>  &quot;power_level&quot;: 75,</span></span>
<span class="line"><span>  &quot;location&quot;: &quot;所在地点：主要活动区域、势力范围&quot;,</span></span>
<span class="line"><span>  &quot;motto&quot;: &quot;组织格言或口号&quot;,</span></span>
<span class="line"><span>  &quot;traits&quot;: [&quot;特征1&quot;, &quot;特征2&quot;, &quot;特征3&quot;],</span></span>
<span class="line"><span>  &quot;color&quot;: &quot;组织代表颜色（如：深红色、金色、黑色等）&quot;,</span></span>
<span class="line"><span>  &quot;organization_members&quot;: [&quot;重要成员1&quot;, &quot;重要成员2&quot;, &quot;重要成员3&quot;]</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【字段说明】</span></span>
<span class="line"><span>- power_level：0-100的整数，表示在世界中的影响力</span></span>
<span class="line"><span>- organization_members：组织内重要成员名字列表（优先关联已有角色）</span></span>
<span class="line"><span>- 成立时间：在background中描述</span></span>
<span class="line"><span>&lt;/output&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;constraints&gt;</span></span>
<span class="line"><span>【必须遵守】</span></span>
<span class="line"><span>✅ 符合世界观：组织设定与项目世界观一致</span></span>
<span class="line"><span>✅ 主题关联：背景与项目主题关联</span></span>
<span class="line"><span>✅ 推动剧情：组织能推动故事发展</span></span>
<span class="line"><span>✅ 有层级结构：内部有明确的层级和结构</span></span>
<span class="line"><span>✅ 势力互动：与其他势力有互动关系</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【命名约束】</span></span>
<span class="line"><span>✅ 如果项目上下文中已有组织，新组织名称风格必须与已有组织一致</span></span>
<span class="line"><span>✅ 组织名称必须符合世界观文化背景</span></span>
<span class="line"><span>✅ 参考已有组织的命名规律（用词习惯、字数、文化风格）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【组织定位要求】</span></span>
<span class="line"><span>✅ 有存在必要性：不是可有可无的背景板</span></span>
<span class="line"><span>✅ 目标合理：不过于理想化或脸谱化</span></span>
<span class="line"><span>✅ 具体细节：描述详细具体，避免空泛</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【格式约束】</span></span>
<span class="line"><span>✅ 纯JSON对象输出，无markdown标记</span></span>
<span class="line"><span>✅ 内容描述中严禁使用特殊符号</span></span>
<span class="line"><span>✅ 专有名词直接书写</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【禁止事项】</span></span>
<span class="line"><span>❌ 输出markdown或代码块标记</span></span>
<span class="line"><span>❌ 在描述中使用特殊符号（引号、方括号等）</span></span>
<span class="line"><span>❌ 过于理想化或脸谱化的设定</span></span>
<span class="line"><span>❌ 空泛的描述</span></span>
<span class="line"><span>❌ 忽略已有组织命名风格，随意编造名称</span></span>
<span class="line"><span>❌ 古代背景使用现代组织名（如&quot;XX科技&quot;&quot;XX集团&quot;）</span></span>
<span class="line"><span>❌ 现代背景使用古代门派名（如&quot;XX宗&quot;&quot;XX阁&quot;）</span></span>
<span class="line"><span>❌ 使用与世界观不匹配的词汇命名</span></span>
<span class="line"><span>&lt;/constraints&gt;</span></span></code></pre></div>`,3)])])}const d=s(t,[["render",e]]);export{_ as __pageData,d as default};
